content:
{
  "sentences": [
    {
      "text": "昨天發生了一件糟糕的事情，我的手機壞掉了。",
      "pinyin": "Zuótiān fāshēng le yī jiàn zāogāo de shìqíng, wǒ de shǒujī huài diào le.",
      "pinyin_numeric": "zuo2tian1 fa1sheng1 le5 yi1 jian4 zao1gao1 de5 shi4qing2, wo3 de5 shou3ji1 huai4 diao4 le5.",
      "translation_en": "A terrible thing happened yesterday—my phone broke.",
      "translation_ko": "어제 끔찍한 일이 발생했어요. 제 핸드폰이 고장 났어요."
    },
    {
      "text": "因為塞車，所以我今天上班遲到了。",
      "pinyin": "Yīnwèi sāichē, suǒyǐ wǒ jīntiān shàngbān chídào le.",
      "pinyin_numeric": "yin1wei4 sai1che1, suo3yi3 wo3 jin1tian1 shang4ban1 chi2dao4 le5.",
      "translation_en": "Because of traffic, I was late for work today.",
      "translation_ko": "교통 체증 때문에 오늘 출근에 지각했어요."
    },
    {
      "text": "他忘記帶鑰匙，結果進不了家門。",
      "pinyin": "Tā wàngjì dài yàoshi, jiéguǒ jìn bù liǎo jiāmén.",
      "pinyin_numeric": "ta1 wang4ji4 dai4 yao4shi5, jie2guo3 jin4 bu4 liao3 jia1men2.",
      "translation_en": "He forgot to bring his keys, so he couldn't get into the house.",
      "translation_ko": "그가 열쇠를 가져오는 걸 잊어버려서 집에 들어갈 수 없었어요."
    },
    {
      "text": "突然下大雨，我沒有帶傘，所以全身都濕了。",
      "pinyin": "Túrán xià dàyǔ, wǒ méiyǒu dài sǎn, suǒyǐ quánshēn dōu shī le.",
      "pinyin_numeric": "tu2ran2 xia4 da4yu3, wo3 mei2you3 dai4 san3, suo3yi3 quan2shen1 dou1 shi1 le5.",
      "translation_en": "It suddenly rained heavily, and I didn't have an umbrella, so I got completely soaked.",
      "translation_ko": "갑자기 큰 비가 내렸는데 우산이 없어서 온몸이 다 젖었어요."
    },
    {
      "text": "我的錢包弄丟了，裡面有我的悠遊卡和信用卡。",
      "pinyin": "Wǒ de qiánbāo nòng diū le, lǐmiàn yǒu wǒ de yōuyóukǎ hé xìnyòngkǎ.",
      "pinyin_numeric": "wo3 de5 qian2bao1 nong4 diu1 le5, li3mian4 you3 wo3 de5 you1you2ka3 he2 xin4yong4ka3.",
      "translation_en": "I lost my wallet, which had my EasyCard and credit card inside.",
      "translation_ko": "제 지갑을 잃어버렸는데 안에 유유카드와 신용카드가 있었어요."
    },
    {
      "text": "因為颱風，所以今天學校停課了。",
      "pinyin": "Yīnwèi táifēng, suǒyǐ jīntiān xuéxiào tíngkè le.",
      "pinyin_numeric": "yin1wei4 tai2feng1, suo3yi3 jin1tian1 xue2xiao4 ting2ke4 le5.",
      "translation_en": "Because of the typhoon, school was canceled today.",
      "translation_ko": "태풍 때문에 오늘 학교가 휴교했어요."
    },
    {
      "text": "他感冒了，所以今天沒有來上班。",
      "pinyin": "Tā gǎnmào le, suǒyǐ jīntiān méiyǒu lái shàngbān.",
      "pinyin_numeric": "ta1 gan3mao4 le5, suo3yi3 jin1tian1 mei2you3 lai2 shang4ban1.",
      "translation_en": "He caught a cold, so he didn't come to work today.",
      "translation_ko": "그가 감기에 걸려서 오늘 출근하지 않았어요."
    },
    {
      "text": "我們先吃飯，然後去看電影，最後再回家。",
      "pinyin": "Wǒmen xiān chīfàn, ránhòu qù kàn diànyǐng, zuìhòu zài huíjiā.",
      "pinyin_numeric": "wo3men5 xian1 chi1fan4, ran2hou4 qu4 kan4 dian4ying3, zui4hou4 zai4 hui2jia1.",
      "translation_en": "We'll eat first, then go see a movie, and finally go home.",
      "translation_ko": "먼저 밥을 먹고, 그다음에 영화를 보러 가고, 마지막으로 집에 갈 거예요."
    },
    {
      "text": "因為地震，所以火車誤點了。",
      "pinyin": "Yīnwèi dìzhèn, suǒyǐ huǒchē wùdiǎn le.",
      "pinyin_numeric": "yin1wei4 di4zhen4, suo3yi3 huo3che1 wu4dian3 le5.",
      "translation_en": "Because of the earthquake, the train was delayed.",
      "translation_ko": "지진 때문에 기차가 지연됐어요."
    },
    {
      "text": "他跟我吵架了，結果我們都不高興。",
      "pinyin": "Tā gēn wǒ chǎojià le, jiéguǒ wǒmen dōu bù gāoxìng.",
      "pinyin_numeric": "ta1 gen1 wo3 chao3jia4 le5, jie2guo3 wo3men5 dou1 bu4 gao1xing4.",
      "translation_en": "He argued with me, and as a result, we were both unhappy.",
      "translation_ko": "그가 저와 싸웠고, 결과적으로 우리 둘 다 기분이 안 좋았어요."
    }
  ]
}
